SELECT emotion_name
FROM emotions
WHERE intensity_scale = (SELECT MAX(intensity_scale) FROM emotions);

SELECT AVG(confidence_level) AS average_confidence
FROM emotion_classifications
WHERE emotion_id = 0;

SELECT AVG(confidence_level) AS avg_confidence
FROM report_details
WHERE report_id = 0;

SELECT emotion_name
FROM emotions
ORDER BY emotion_name ASC;

SELECT emotion_name
FROM emotions
WHERE emotion_id = 1;

SELECT emotion_name 
FROM emotions 
ORDER BY emotion_name;
